arguments.file_text:
Span<nint> values = stackalloc nint[] { 1, 2, 3, 4, 5 };

nint sum = 0;
for (int i = 0; i < values.Length; i++)
    sum += values[i];

Console.WriteLine($"Span<nint> length: {values.Length}");
Console.WriteLine($"Sum: {sum}");
Console.WriteLine($"nint size: {nint.Size} bytes");

// Also test nuint
Span<nuint> unsigned = stackalloc nuint[] { 10, 20, 30 };
Console.WriteLine($"Span<nuint> length: {unsigned.Length}, first: {unsigned[0]}");

